    adjacency = {
        "A": {"B": {"C": {"D": 0}}},
        "B": {"C": {"E": 1}},
        "C": {"D": 2}
    }

    for node, neighbor in graph.items():
        if isinstance(neighbor, dict):
            adjacency[node] = {
                "type": type(neighbor),
                "value": len(neighbor)
            }

        elif isinstance(neighbor, list):
            for value_list in neighbor:
                adjacency[node][key=value_list].append((
                    node,
                    (
                        value_list.index(),
                        value_list.pop()
                    ))
                )

    return adjacency
